import useNewsPage from "./components/useNewsPage.vue";
import useDownloadPage from "./components/useDownloadPage.vue";
import useAboutPage from "./components/useAboutPage.vue";
import useAuthorPage from "./components/useAuthorPage.vue";

export default {
  name: "App",
  components: {
    useHeader,
    useNewsPage,
    useDownloadPage,
    useAboutPage,
    useAuthorPage,
  },
  data() {
    return {
      currentTab: "useNewsPage",
    };
  },
  methods: {
    changeTab(page) {
      this.currentTab = `use${page}Page`;
    }
  }
}
</script>

