<template>
  <h1>Новости</h1>
  <div class="news" v-if="news.length > 0">
    <useArticle
      :article="article"
      v-for="article in news"
      :key="article.id"
    ></useArticle>
  </div>
  <h3 v-else>Загружаем...</h3>
</template>

<script setup>
import useArticle from "./useArticle.vue";
import { useScroll } from "@vueuse/core";
import { ref } from "vue";
import { onMounted, watch } from "vue";

import { createClient } from "@supabase/supabase-js";
const supabaseUrl = "https://dwoqqjzleufxugrqmapb.supabase.co";
const supabaseKey =
  "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImR3b3FxanpsZXVmeHVncnFtYXBiIiwicm9sZSI6ImFub24iLCJpYXQiOjE2NzUzOTI5MTksImV4cCI6MTk5MDk2ODkxOX0.CoXJd6IwUWwU4vPgJeaIuKzq7PczY9Tup2g_k_TaSvs";
const supabase = createClient(supabaseUrl, supabaseKey);

const { arrivedState } = useScroll(document);

watch(arrivedState, async () => {
  if (arrivedState.bottom) await fetchNews();
});

const news = ref([]);

onMounted(() => {
  fetchNews();
});

async function fetchNews() {
  const { data, error } = await supabase
    .from("news")
    .select()
    .range(news.value.length, news.value.length + 4)
    .order("id", { ascending: false });
  console.log(error, data);
  news.value.push(...data);
}
</script>

<style>
.news {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 20px;
  overflow-y: scroll;
  height: 100%;
  padding: 0 1rem 1rem 1rem;
}
</style>