<template>
  <article>
    <div class="header">
      <img
        src="../assets/logo.png"
        alt="Изображение пользователя, который оставил запись."
      />
      <div class="about">
        <div class="author">
          <a href="https://vk.com/neoshimathebest"
            >@{{ article.patchnoteAuthor }}</a
          >
          <img src="../assets/verified.png" alt="Официальный пользователь." />
        </div>
        <p class="time">{{ formattedTime }}</p>
        <font-awesome-icon icon="fa-solid fa-square-check" />
      </div>
    </div>
    <div class="content">
      <h1>{{ article.patchnoteName }}</h1>
      <div v-html="textOutput" class="content__body"></div>
    </div>
  </article>
</template>

<script>
import * as moment from "moment";
import "moment/locale/ru";

import { marked } from "marked";

const renderer = new marked.Renderer();
const renderListitem = renderer.listitem;
const renderList = renderer.list;

renderer.listitem = function (text) {
  let html = renderListitem(text);

  if (html.includes("<input")) {
    html = html.replace("<li>", "<li class='task-list-item'>");
  }

  return html;
};

renderer.list = function (text) {
  let html = renderList(text);

  if (html.includes("<input")) {
    html = html.replace("<ul>", "<ul class='task-list'>");
  }

  return html;
};

marked.use({ renderer });

export default {
  name: "useArticle",
  computed: {
    formattedTime() {
      return moment(this.article.patchnoteDate).format("D MMMM в h:mm");
    },
    textOutput() {
      return marked(this.article.patchnoteText);
    },
  },
  props: {
    article: {},
  },
};
</script>

<style lang="scss">
article {
  border: 1px solid black;
  background-color: #202435;
  padding: 20px;
  box-sizing: border-box;
  border-radius: 8px;
  border: 1px solid hsl(0deg 0% 100%/4%);
  max-width: 640px;
  width: 100%;
  .header {
    display: flex;
    gap: 7px;
    img {
      width: 36px;
      height: 36px;
      border-radius: 5px;
    }
    .time {
      color: #6f727d;
    }
    .about {
      .author {
        display: flex;
        align-items: center;
        gap: 5px;
        a {
          color: #c9cccf;
          font-size: 15px;
          margin: 0;
          transition: opacity 0.3s;
          text-decoration: none;
          &:visited {
            color: #c9cccf;
          }
          &:hover {
            opacity: 0.5;
          }
        }
        img {
          display: none;
          width: 15px;
          height: 15px;
        }
      }
      p {
        font-size: 13px;
        margin: 0;
      }
    }
  }
  .content {
    h1 {
      font-size: 22px;
      font-weight: 700;
      margin: 10px 0px;
      margin-bottom: 10px;
    }
    img {
      max-width: 100%;
      border-radius: 8px;
    }
    ul {
      li {
        input[type="checkbox"] {
          height: 16px;
          width: 16px;
          margin: 0;
          -webkit-appearance: none;
          -moz-appearance: none;
          -o-appearance: none;
          appearance: none;
          border: 1px solid #34495e;
          border-radius: 2px;
          outline: none;
          transition-duration: 0.3s;
          background-color: #323547;
          cursor: pointer;
          display: inline-block;
          position: relative;
          &:checked {
            border: 1px solid #323547;
            background-color: #151824;
            &::before {
              content: '';
              position: absolute;
              width: 50%;
              height: 50%;
              top: 0;
              left: 0;
              background-color: 323547;
            }
          }
        }
      }
    }
    a {
      color: #80b7ff;
      text-decoration: none;
      transition: opacity 0.3s;
      &:hover {
        opacity: 0.5;
      }
    }
    &__body {
      .task-list {
        padding-left: 0;

        .task-list-item {
          list-style: none;
        }
      }

      p {
        text-align:justify;
      }

      p,
      pre {
        margin: 10px 0;
      }

      & > :last-child {
        margin-bottom: 0;
      }

      p code {
        background: #323547;
        color: #80b7ff;
        font-size: 16px;
        padding: 2px 4px;
        border-radius: 4px;
      }

      pre {
        margin-block-start: 1em;
        margin-block-end: 1em;
        margin-inline-start: 0px;
        margin-inline-end: 0px;
        code {
          background-color: #323547;
          padding: 8px;
          border-radius: 6px;
        }
      }

      hr {
        border-color: #3a3d50;
      }

      blockquote {
        padding-left: 10px;
        border-left: 5px solid #3a3d50;
        border-top-left-radius: 2px;
        border-bottom-left-radius: 2px;
        font-style: italic;
        margin-left: 20px;
      }
    }
  }
}
</style>